    int T;
    cin &gt;&gt; T;
    while(T--){
        unsigned long long A, B, X, Y;
        cin &gt;&gt; A &gt;&gt; B &gt;&gt; X &gt;&gt; Y;

        if(A &gt;= B){
            cout &lt;&lt; 0 &lt;&lt; "\n";
            continue;
        }

        // If both operations are ineffective.
        if(X == 1 &amp;&amp; Y == 1){
            cout &lt;&lt; -1 &lt;&lt; "\n";
            continue;
        }

        // Handle cases when only one operation is effective.
        if(Y == 1){
            if(X == 1){
                cout &lt;&lt; -1 &lt;&lt; "\n";
            } else {
                long long ops = 0;
                __int128 currentA = A;
                while(currentA &lt; B){
                    currentA *= X;
                    ops++;
                }
                cout &lt;&lt; ops &lt;&lt; "\n";
            }
            continue;
        }

        if(X == 1){
            long long divOps = 0;
            unsigned long long currentB = B;
            bool possible = false;
            while(true){
                if(A &gt;= currentB){
                    possible = true;
                    break;
                }
                if(currentB == 0)
                    break;
                unsigned long long nextB = currentB / Y;
                if(nextB == currentB)
                    break;
                currentB = nextB;
                divOps++;
            }
            if(possible)
                cout &lt;&lt; divOps &lt;&lt; "\n";
            else
                cout &lt;&lt; -1 &lt;&lt; "\n";
            continue;
        }

        // General case: both X &gt; 1 and Y &gt; 1.
        long long best = LLONG_MAX;
        unsigned long long currentB = B;
        for (long long d = 0; ; d++){
            if(A &gt;= currentB){
                if(d &lt; best)
                    best = d;
            } else {
                long long m = 0;
                __int128 currentA = A;
                while(currentA &lt; currentB){
                    currentA *= X;
                    m++;
                }
                if(m + d &lt; best)
                    best = m + d;
            }
            if(currentB == 0)
                break;
            unsigned long long nextB = currentB / Y;
            if(nextB == currentB)
                break;
            currentB = nextB;
        }
        cout &lt;&lt; best &lt;&lt; "\n";
    }
    return 0;
}
